    contact: "KONTAKT",
    rights: "Alle Rechte vorbehalten | Drazba.si",
    verifyNotice: "Profil nicht verifiziert. Identitätsprüfung für Gebote erforderlich (Art. 18 SP).",
    verifyAction: "JETZT VERIFIZIEREN",
    createAuction: "AUKTION ERSTELLEN",
